import './Snackbar.scss';

import { IconButton } from ':components/IconButton';
import { useDeviceSize } from ':helpers';
import { useComponentDidMount } from ':helpers/use-component-did-mount';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import {
	snackbarElasticTextMarginBottom,
	snackbarTextFontLineHeight,
	snackbarTextMarginTop,
} from '@beeline/design-tokens/js/tokens/components/snackbar';
import type { FC } from 'react';
import React, { useEffect, useRef, useState } from 'react';

import { classNames } from '../../helpers/classnames';
import { Button } from '../Button';
import { Typography } from '../Typography';
import type { SnackbarProps } from './Snackbar.types';

export const Snackbar: FC<SnackbarProps> = ({
	open = false,
	message,
	delay = 3000,
	onClose,
	action,
	closeButton = false,
	horizontal = 'right',
	vertical = 'bottom',
	variant = 'elastic',
	className,
}) => {
	const isComponentMounted = useComponentDidMount();
	const { isExtraSmallDevice } = useDeviceSize();
	const onCloseRef = useRef(onClose);
	onCloseRef.current = onClose;

	const _horizontal = isExtraSmallDevice ? 'center' : horizontal;
	// Используем проп vertical независимо от размера устройства
	const _vertical = vertical;
	const snackbarRef = useRef<HTMLDivElement>(null);
	const [multilineText, setTextState] = useState<boolean>(false);
	// todo если текст многострочный, то стилистика меняется, наверное, можно убрать из зависимостей всё, кроме isComponentMounted
	// так как компонент должен быть статичный после отображения, но пока так
	useEffect(() => {
		const blockHeight: number =
			Number.parseInt(snackbarTextFontLineHeight) +
			Number.parseInt(snackbarTextMarginTop) +
			Number.parseInt(snackbarElasticTextMarginBottom);
		setTextState(snackbarRef?.current?.offsetHeight > blockHeight);
	}, [isComponentMounted, open, message, action, variant]);

	const actionButton = action && (
		<Button variant="plain" size="small" className="dsb_snackbar-body-action" onClick={action?.onClick}>
			{action?.label || 'Закрыть'}
		</Button>
	);

	const [isOpen, setIsOpen] = useState(open);
	const [isVisible, setIsVisible] = useState(open);
	const transitionEndRef = useRef(false);

	// Обновляем состояния при изменении пропса open
	useEffect(() => {
		if (open) {
			setIsVisible(true);
			setIsOpen(true);
			transitionEndRef.current = false;
		} else {
			// Только меняем isOpen, isVisible изменится после перехода
			setIsOpen(false);
		}
	}, [open]);

	// Обработчик завершения перехода
	useEffect(() => {
		const node = snackbarRef.current;
		if (!node) {
			return;
		}

		const handleTransitionEnd = (event: TransitionEvent) => {
			if (event.propertyName === 'opacity' && !isOpen) {
				// Скрываем компонент только после завершения перехода
				setIsVisible(false);
			}
		};

		node.addEventListener('transitionend', handleTransitionEnd);
		return () => node.removeEventListener('transitionend', handleTransitionEnd);
	}, [isOpen]);

	// Автоматическое закрытие по таймеру
	useEffect(() => {
		if (isOpen && delay) {
			const timer = setTimeout(() => {
				closeAction();
			}, delay);

			return () => clearTimeout(timer);
		}
	}, [delay, isOpen]);

	const closeAction = () => {
		// Предотвращаем повторное закрытие
		if (!isOpen) {
			return;
		}

		onCloseRef.current?.();
		setIsOpen(false);
	};

	// Если компонент не должен быть видимым, возвращаем undefined
	if (!isVisible) {
		return;
	}

	return (
		<div className="dsb_snackbar-wrapper" data-testid="Snackbar">
			<div
				role="alert"
				aria-live="polite"
				aria-atomic="true"
				aria-hidden={!isOpen}
				ref={snackbarRef}
				className={classNames(
					'dsb_snackbar',
					isOpen ? 'dsb_snackbar__open' : 'dsb_snackbar__closing',
					`dsb_snackbar__${_horizontal}`,
					`dsb_snackbar__${_vertical}`,
					'inverseTheme',
					`dsb_snackbar__${variant}`,
					isExtraSmallDevice && 'dsb_snackbar-mobile',
					multilineText && 'dsb_snackbar__multiline',
					className,
				)}
			>
				<div className="dsb_snackbar-body">
					<div className="dsb_snackbar-body_content-line">
						<Typography
							variant="body3"
							className={classNames(
								'dsb_snackbar-body-message',
								action && 'dsb_snackbar-body-message__with-action',
								`dsb_snackbar-body-message__${variant}`,
								closeButton && 'dsb_snackbar-body-message__with-close',
							)}
						>
							{message}
						</Typography>
						{actionButton}
					</div>
					{closeButton && (
						<div className="dsb_snackbar-body_close-block">
							<IconButton iconName={Icons.Close} onClick={closeAction} />
						</div>
					)}
				</div>
			</div>
		</div>
	);
};
